<script>
(function () {
    var root = document.querySelector('.nce-footer-move[data-nce-footer-move]');
    if (!root) return;
    function reveal() {
        root.classList.add('nce-footer-move--inview');
    }
    try {
        if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
            reveal();
            return;
        }
    } catch (e) {}
    if (!('IntersectionObserver' in window)) {
        reveal();
        return;
    }
    var io = new IntersectionObserver(
        function (entries) {
            entries.forEach(function (entry) {
                if (entry.isIntersecting) {
                    reveal();
                    io.disconnect();
                }
            });
        },
        { threshold: 0.15, rootMargin: '0px 0px -10% 0px' }
    );
    io.observe(root);
})();
</script>
